const cfg = $('Prepare API and Comment Data').first().json;
const raw = $json;

function firstImageUrl(image) {
  return Array.isArray(image?.url_list) ? image.url_list[0] || null : null;
}

const root = Array.isArray(raw) ? raw[0] : raw;
const data = root?.data || {};
const comments = Array.isArray(data.comments) ? data.comments : [];

function cleanUser(user = {}) {
  return {
    uid: user.uid ?? null,
    shortId: user.short_id ?? null,
    secUid: user.sec_uid ?? null,
    nickname: user.nickname ?? null,
    signature: user.signature ?? null,
    uniqueId: user.unique_id ?? null,
    avatarThumb: firstImageUrl(user.avatar_thumb),
    avatarMedium: firstImageUrl(user.avatar_medium),
    isVerified: user.is_verified ?? null,
    followStatus: user.follow_status ?? null,
    followerCount: user.follower_count ?? null,
    customVerify: user.custom_verify ?? null,
    enterpriseVerifyReason: user.enterprise_verify_reason ?? null,
    verificationType: user.verification_type ?? null,
    region: user.region ?? null
  };
}

function cleanTopLevelComment(comment) {
  return {
    commentId: comment.cid ?? null,
    text: comment.text ?? null,
    awemeId: comment.aweme_id ?? null,
    createTime: comment.create_time ?? null,
    likeCount: comment.digg_count ?? null,
    status: comment.status ?? null,
    replyCommentTotal: comment.reply_comment_total ?? null,
    replyId: comment.reply_id ?? null,
    replyToReplyId: comment.reply_to_reply_id ?? null,
    isAuthorDigged: comment.is_author_digged ?? null,
    userDigged: comment.user_digged ?? null,
    isHot: comment.is_hot ?? null,
    labelText: comment.label_text ?? null,
    labelType: comment.label_type ?? null,
    contentType: comment.content_type ?? null,
    imageList: comment.image_list ?? null,
    user: cleanUser(comment.user)
  };
}

const cleanedComments = comments.map(cleanTopLevelComment);
const selectedComment = cleanedComments.find(comment => Number(comment.replyCommentTotal || 0) > 0) || null;

return [{
  json: {
    baseUrl: cfg.baseUrl,
    token: cfg.token,
    awemeId: cfg.awemeId,
    commentPage: cfg.commentPage,
    replyPage: cfg.replyPage,
    commentsMeta: {
      statusCode: data.status_code ?? null,
      cursor: data.cursor ?? null,
      hasMore: data.has_more ?? null,
      total: data.total ?? null,
      replyStyle: data.reply_style ?? null,
      hotsoonFilteredCount: data.hotsoon_filtered_count ?? null,
      foldedCommentCount: data.folded_comment_count ?? null,
      logId: data.extra?.logid ?? null,
      imprId: data.log_pb?.impr_id ?? null
    },
    totalCommentsReturned: cleanedComments.length,
    hasCommentWithReplies: Boolean(selectedComment?.commentId),
    commentId: selectedComment?.commentId || null,
    selectedComment,
    comments: cleanedComments,
    rawCommentsResponse: raw
  }
}];

const selectedData = $('Select Comment with Replies').first().json;
const rawReplies = $json;

function firstImageUrl(image) {
  return Array.isArray(image?.url_list) ? image.url_list[0] || null : null;
}

const root = Array.isArray(rawReplies) ? rawReplies[0] : rawReplies;
const data = root?.data || {};
const replies = Array.isArray(data.comments) ? data.comments : [];

function cleanUser(user = {}) {
  return {
    uid: user.uid ?? null,
    shortId: user.short_id ?? null,
    secUid: user.sec_uid ?? null,
    nickname: user.nickname ?? null,
    signature: user.signature ?? null,
    uniqueId: user.unique_id ?? null,
    avatarThumb: firstImageUrl(user.avatar_thumb),
    avatarMedium: firstImageUrl(user.avatar_medium),
    isVerified: user.is_verified ?? null,
    followStatus: user.follow_status ?? null,
    followerCount: user.follower_count ?? null,
    customVerify: user.custom_verify ?? null,
    enterpriseVerifyReason: user.enterprise_verify_reason ?? null,
    verificationType: user.verification_type ?? null,
    region: user.region ?? null
  };
}

function cleanReply(reply) {
  return {
    replyId: reply.cid ?? null,
    text: reply.text ?? null,
    awemeId: reply.aweme_id ?? null,
    rootCommentId: reply.root_comment_id ?? null,
    parentCommentId: reply.reply_id ?? null,
    replyToReplyId: reply.reply_to_reply_id ?? null,
    level: reply.level ?? null,
    createTime: reply.create_time ?? null,
    likeCount: reply.digg_count ?? null,
    status: reply.status ?? null,
    commentReplyTotal: reply.comment_reply_total ?? null,
    userDigged: reply.user_digged ?? null,
    isAuthorDigged: reply.is_author_digged ?? null,
    isHot: reply.is_hot ?? null,
    labelText: reply.label_text ?? null,
    labelType: reply.label_type ?? null,
    contentType: reply.content_type ?? null,
    isFolded: reply.is_folded ?? null,
    imageList: reply.image_list ?? null,
    user: cleanUser(reply.user)
  };
}

const cleanedReplies = replies.map(cleanReply);

return [{
  json: {
    awemeId: selectedData.awemeId,
    commentPage: selectedData.commentPage,
    replyPage: selectedData.replyPage,
    hasCommentWithReplies: selectedData.hasCommentWithReplies,
    commentsMeta: selectedData.commentsMeta,
    selectedComment: selectedData.selectedComment,
    repliesMeta: {
      statusCode: data.status_code ?? null,
      cursor: data.cursor ?? null,
      mergeCursor: data.merge_cursor ?? null,
      hasMore: data.has_more ?? null,
      total: data.total ?? null,
      logId: data.extra?.logid ?? null,
      imprId: data.log_pb?.impr_id ?? null
    },
    totalCommentsReturned: selectedData.totalCommentsReturned,
    replyCountReturned: cleanedReplies.length,
    comments: selectedData.comments,
    replies: cleanedReplies,
    rawCommentsResponse: selectedData.rawCommentsResponse,
    rawRepliesResponse: rawReplies
  }
}];

const data = $json;

return [{
  json: {
    awemeId: data.awemeId,
    commentPage: data.commentPage,
    replyPage: data.replyPage,
    hasCommentWithReplies: false,
    message: 'No top-level comment with reply_comment_total greater than 0 was found in the returned comments page. Review the raw comments response or try another commentPage value.',
    commentsMeta: data.commentsMeta,
    totalCommentsReturned: data.totalCommentsReturned,
    comments: data.comments,
    rawCommentsResponse: data.rawCommentsResponse
  }
}];
